     */
    bool Deserialize(uint8_t& value);

    /**
     * @brief 反序列化一个16位整数
     * @param value 输出参数
     * @return 是否成功
     */
    bool Deserialize(uint16_t& value);

    /**
     * @brief 反序列化一个32位整数
     * @param value 输出参数
     * @return 是否成功
     */
    bool Deserialize(uint32_t& value);

    /**
     * @brief 反序列化一个64位整数
     * @param value 输出参数
     * @return 是否成功
     */
    bool Deserialize(uint64_t& value);

    /**
     * @brief 反序列化一个32位浮点数
     * @param value 输出参数
     * @return 是否成功
     */
    bool Deserialize(float& value);

    /**
     * @brief 反序列化一个64位浮点数
     * @param value 输出参数
     * @return 是否成功
     */
    bool Deserialize(double& value);

    /**
     * @brief 反序列化一个布尔值
     * @param value 输出参数
     * @return 是否成功
     */
    bool Deserialize(bool& value);

    /**
     * @brief 反序列化一个字符串
     * @param str 输出参数
     * @return 是否成功
     */
    bool Deserialize(std::string& str);

    /**
     * @brief 反序列化原始数据块
     * @param output 输出缓冲区
     * @param size 数据大小
     * @return 是否成功
     */
    bool DeserializeRaw(void* output, size_t size);

    /**
     * @brief 反序列化一个容器
     * @param container 输出参数
     * @return 是否成功
     */
    template<typename T>
    bool DeserializeContainer(std::vector<T>& container);

    /**
     * @brief 获取剩余可读字节数
     * @return 字节数
     */
    size_t GetBytesRemaining() const;

    /**
     * @brief 检查是否已到达末尾
     * @return 如果已到达末尾则返回true
     */
    bool IsEOF() const;

    /**
     * @brief 重置反序列化器到起始位置
